insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2COO3','ov2-2025','COORDINATOR','3','Faiz Irhab, Devika, Nisrina, Dzaki, Daniel','Menetapkan Status ''Overtime''','2025-09-04',null,'2025-09-26',null,'Tugas yang belum selesai harus ditandai dengan status overtime, lalu lakukan reminder terhadap PIC yang memegang tugas tersebut, jika tugas sangat diperlukan oleh divisi lain atau sangat penting untuk diselesaikan maka koordinator diwajibkan mengambil alih tugasnya. Worst case, tugasnya pun tidak bisa diselesaikan koordinator karena beberapa faktor, minta bantuan PIC OV',null,'done');
