insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2LIA1','ov2-2025','LO','1','Devika, Mba Tasha, Daniel','Buat Spreadsheet Liaison Officer','2025-09-04',null,'2025-09-05',null,'Tugas ini bedasarkan Evaluasi OV sebelumnya, Koordinator diharapkan membuat sps yang mendata Broadcast, Contact Ketua Departemen HMSI untuk dimintai tolong disebarkan BC nya, assign penugasan siapa yang bertanggung jawab menghubungi Ketua Departemen HMSI dan termasuk Deadline Pengerjaan. Spreadsheet dapat dibuat sebebasnya sesuai kebutuhan LO Contoh Spreadsheet LO : LINK','LO Ormawa Visit 2 2025','done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2LIA2','ov2-2025','LO','2',null,'Buat dan Bagikan Broadcast per Departemen','2025-09-04',null,'2025-09-14',null,'Ormawa Visit Broadcasts Tujuan utama dari Broadcast ini ialah melakukan ajakan untuk menjadi peserta OV dengan mengisi Spreadsheet Daftar Peserta OV, Broadcast akan dibagikan per Departemen HMSI Buat broadcast template agar dapat diedit oleh staff dan intern ketika reach per Departemen HMSI Broadcast akan ada 8 sesuai jumlah Departemen HMSI selain EA Evaluasi dari OV sebelumnya : Ketua per Departemen-lah yang dimintai untuk membagikan bc ke Grup WA Departemennya',null,'done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2LIA3','ov2-2025','LO','3',null,'Buat dan Bagikan Broadcast group wa Niskalarasi','2025-09-04',null,'2025-09-25',null,'[BC HARUS DIKONFIRMASI SEBELUM DISEBAR] Broadcast berisi - Clickbait - Foto 1x1 tulisan OV (Opsional) - Contact Person (1 PIC & 1 LO) - Tagar - Emoticon Topik Broadcast dan Broadcast harus disebarkan saat: - 15 September [Pengenalan OV, Jadwal & Tempat dan Pengisian SPS Daftar Peserta OV] - 19 September [Reminder Pengisian SPS Daftar Peserta OV dan Jadwal & Tempat] - H-7 Acara (20 September) [Jadwal & Tempat, Rundown, OV Guidebook & Konten Marketing] - H-3 Acara (24 September) [Jadwal & Tempat, Rundown & OV Guidebook, Himbauan Tumbler] - H-1 Acara (26 September) [Jadwal & Tempat, Rundown & OV Guidebook, Himbauan Tumbler] - Hari H Acara, Pagi (27 September) [Jadwal & Tempat, Rundown & OV Guidebook] - 2 Jam Setelah Acara (27 September) [Ucapan Terimakasih] Link yang terlalu panjang dapat dishorten, Shortener ITS : LINK Buat Google Dokumen (atau bisa pakai sps LO) yang mendata seluruh broadcast yang akan dan sudah disebar, bisa gunakan contoh sebagai referensi Contoh : LINK',null,'done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2LIA4','ov2-2025','LO','4',null,'Menyebarkan hasil dari ''Daftar peserta HMSI'' ke Staff OV lainnya','2025-09-19',null,'2025-09-22',null,'Spreadsheet ''Daftar peserta HMSI'' dibutuhkan oleh teman staff yang lain, contohnya untuk presensi',null,'done');
