insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2EVE4','ov2-2025','EVENT','4','Crystal, Burhan','Pembuatan Rundown','2025-09-04',null,'2025-09-13',null,'Rundown kasaran sudah ada di Proposal Ormawa Visit : LINK Outputnya berupa 2 Dokumen, yaitu Rundown untuk Panitia OV dan Rundown untuk Peserta Saran perubahan dan fiksasi lebih lanjut sangat diharapkan, hal ini juga melibatkan Himpunan Eksternal Contoh Rundown Panitia : LINK',null,'done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2EVE5','ov2-2025','EVENT','5','Avatar, Mba Dilla','Pembuatan Ormawa Visit Guidebook','2025-09-04',null,'2025-09-19',null,'Ormawa Visit Guidebook hanya perlu diganti isinya beberapa, buat copy dari Guidebook sebelumnya dan ganti semua isinya dengan sesuai. OV Guidebook sebelumnya : LINK','https://docs.google.com/document/d/1yYGR5X39DIzqTwISOv5zq03c8wwGKz_4LqOXOuhvEb8/edit?tab=t.ls09td51ccyk https://intip.in/GuidebookOrmawaVisit','done');
