insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2EVE7','ov2-2025','EVENT','7','Naila, Burhan, Fadhiil','Merencanakan Gladi Bersih dan Menyebarkan Broadcast-nya','2025-09-14',null,'2025-09-22',null,'Gladi bersih akan sangat diharapkan terlaksana saat H-1 acara, gladi ini akan sangat mengandalkan Juklak Juknis yang sudah dibuat PIC OV, lokasi gladi bersih diharapkan lokasi OV sebenarnya. Isi dari broadcast yang disebarkan ke seluruh panitia OV : - Jadwal & Tempat - Pelatihan MC - Uji coba Operator - Uji coba Time Keeper - Penataan Ruang - Rencana Tempat Parkir Peserta - Design awal Creative Corner - Design dan Uji coba Photobooth OV Contoh Broadcast : LINK',null,'done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2EVE8','ov2-2025','EVENT','8','Hayyu, Burhan, Crystal','Mempersiapkan & Evaluasi Games','2025-09-14',null,'2025-09-24',null,'Games berupa PPT, Konsep game dibebaskan dengan syarat dapat dimainkan oleh semua peserta OV, nantinya game akan memiliki tim sesuai Pasangan Departemen FGD Evaluasi dari OV sebelumnya : MC dan penghitung poin susah menentukan tim mana yang mengangkat tangan duluan untuk menjawab gamesnya, cari solusi alternatif Contoh Game sebelumnya : LINK','https://docs.google.com/presentation/d/1HgmFKCymdaDpqR_GJwABXo_4vsPguycIzxla5uYoqj8/edit?usp=sharing','done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2EVE9','ov2-2025','EVENT','9',null,'Menjadi Petugas Penghitung Poin Games dan Menentukan Pemenang Games','2025-09-19',null,'2025-09-26',null,'Petugas akan mencatat poin atau kredit dari tim yang menjawab benar, tim akan disesuaikan dengan Pasangan Departemen FGD. Outputnya akan hanya ada 1 tim pemenang atau 2 Departemen Himpunan yang sepasang FGD',null,'done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2EVE10','ov2-2025','EVENT','10','Franz, Juno','Menjadi MC, membuat Script MC dan koordinasi dengan MC pihak lain','2025-09-04',null,'2025-09-24',null,'Master of Ceremony berjumlah 2 Orang, satu dari HMSI dan satu lagi dari Himpunan Eksternal. Gender MC harus berlawanan Untuk script MC diperbolehkan memilih 2 jenis, diprint atau baca pakai Handphone, karena bedasarkan Evaluasi OV sebelumnya, script MC sudah diprint dan dilaminating namun perlu banyak revisi dan akhirnya print ulang. Dokumen Script MC harus publik dan linknya diinput di kolom result dan superlink Contoh Script MC OV sebelumnya : LINK','https://docs.google.com/document/d/1Szs43wqbZlGvKsizwq4xQKuIlYcd7k7yEwPf3FdRq-E/edit?tab=t.g33rflxshscz','done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2EVE11','ov2-2025','EVENT','11','Avatar, Mas Agung','Pembuatan Google Form feedback acara','2025-09-04',null,'2025-09-25',null,'Google Form Feedback nantinya diubah ke kode QR yang ditampilkan pada akhir acara, jika sudah jadi taro QR pada Slide PPT dan sampaikan Operator untuk ditampilkan Contoh Google Form Feedback : LINK Contoh Slide PPT Feedback : LINK Link to QR : LINK','https://docs.google.com/presentation/d/1pbypEDPSJyPhjDBPvx1WfoeNmGgmhLJy2T08nwhPLZA/edit?usp=sharing','done');
