insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2OPE3','ov2-2025','OPERATIONAL','3','Faiz Irhab','Menyiapkan Semua Kebutuhan Peminjaman Tempat di Lokasi OV','2025-09-04',null,'2025-09-25',null,'[Mohon tugas ini dilakukan secepatnya, karena lokasi peminjaman tidak selalu available] Segala kebutuhan dari menghubungi peminjaman tempat, biaya THL peminjaman ruang, dokumen yg dibutuhkan, ttd dll. ttd yang dibutuhkan bisa diserahkan kepada Sekretaris EA (Nisrina) ketika dokumennya sudah jadi Beberapa opsi lokasi OV yang disarankan PIC OV ialah (terurut prioritas): - Pascasarjana, Auditorium Lantai 3 - Smartclass 1101-1102 - Tower 2, Auditorium Lantai 2 - Outdoor di area depan gedung 2 gedung 1 Sisfor Peminjaman tempat juga harus include gladi bersih OV. Spreadsheet Peminjaman Ruang',null,'done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2OPE4','ov2-2025','OPERATIONAL','4','Faiz Irhab, Ali','Survey lokasi Ormawa Visit','2025-09-04',null,'2025-09-25',null,'Hasilnya berupan dokumen/gdrive yang menyertakan foto dan video dari tempat lokasi OV, nanti hasil dari survey ini akan digunakan untuk merencakan peletakan dari Creative Corner, Photobooth OV, gambaran untuk Himpunan Eksternal, gambaran muat berapa peserta serta gambaran penempatan tempat duduk per pasangan Departemen Himpunan, juga saat FGD. Survey lokasi bisa saja opsional jika sangat tidak memungkinkan dari berbagai faktor.',null,'done');
