insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2CRE2','ov2-2025','CREATIVE','2','Dzaki','Folder Google Drive Creative','2025-09-04',null,'2025-09-07',null,'Memuat keseluruhan hasil dokumentasi dan design yang dibuat atau direquest, pastikan tautan public Folder berisi : - Dokumentasi Survei Tempat - Logo HMSI dan Logo Himpunan Eksternal - Dokumentasi Acara IM - Dokumentasi Acara EA (foto panitia, Creative Corner dll) - Hasil semua foto dari Photobooth dan desain Twibbon Photobooth - Semua desain yang direquest atau dibuat (Poster Feeds, CueCard MC, Banner, ID Card, Desain Plakat Ormawa Lain, Bumper, Twibbon Photobooth)',null,'done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2CRE3','ov2-2025','CREATIVE','3',null,'Dokumen Konsep Creative Corner','2025-09-04',null,'2025-09-14',null,'Dokumen nantinya memuat brief konsep desain referensi untuk Creative Corner, alat dan bahan apa saja yang dibutuhkan, penempatan CC dan kapan para peserta dibolehkan untuk mengisi (cek Rundown untuk referensi) CC merupakan alat untuk para peserta melampiaskan sisi seninya pada pelaksanaan Ormawa Visit, peserta dibolehkan menulis atau menggambar apapun selama tidak mengandung SARA. Biasanya CC berupa Papan Tulis dengan Spidol serta Sticky Notes. Referensi Creative Corner sebelumnya : LINK',null,'done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2CRE4','ov2-2025','CREATIVE','4','Alwida','Menjadi Petugas Creative Corner','2025-09-19',null,'2025-09-25',null,'Petugas diharapkan bisa mendesain Creative Corner saat Gladi Bersih dengan alat dan bahan sesuai dokumen konsep Referensi Creative Corner sebelumnya : LINK',null,'done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2CRE5','ov2-2025','CREATIVE','5','Thalia','Dokumen Konsep Photobooth Ormawa Visit','2025-09-04',null,'2025-09-17',null,'Berupa Photobooth tanpa print yang dapat digunakan peserta saat acara maupun selesai acara, nantinya foto-foto akan terkumpul lewat Gdrive yang dapat diakses lewat scan QR code. Foto akan memiliki twibbon tema OV. Dokumen nantinya berisi konsepan dari photobooth (angle kamera, background, software yang dipakai), desain dari twibbon photobooth, tempat penyimpanan dan pembagian fotonya, tampilan hasil foto, dekorasi dan aksesoris photobooth, lokasi penempatan serta alat dan bahan untuk photobooth Sangat dianjurkan Photobooth memiliki tema, perihal ini dibebaskan temanya Referensi photobooth bisa meniru ide dari APP : LINK Referensi twibbon : LINK Link to QR code : LINK','https://docs.google.com/document/d/1IE4MC9pCxu1fbPfoHn0C7ZiVn9fsqG0MP-_zo_5HePY/edit?usp=drivesdk','done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2CRE6','ov2-2025','CREATIVE','6','Fairuz','Menjadi Petugas Photobooth','2025-09-19',null,'2025-09-25',null,'Dibutuhkan minimal satu orang untuk job ini Petugas photobooth bertanggung jawab mengambil foto, menyarankan pose kepada peserta, pengarahan posisi foto peserta dan bertanggung jawab menjaga booth serta aksesoris',null,'done');
