insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('2CRE8','ov2-2025','CREATIVE','8','Mas Fauzan','Desain Poster Feeds Ormawa Visit','2025-09-04',null,'2025-09-17',null,'Feeds Ormawa Visit sudah memiliki template dari IM, ganti informasi penting pada template seperti jadwal dan fotonya lalu request kepada IM untuk dipublikasikan Template feeds berada di Figma EA yang diberikan IM, tanyakan kepada staff jika intern tidak bisa mengakses Contoh Feeds : LINK','https://drive.google.com/drive/folders/188jN3fHj3N7P6nhlNSEovrlsqTVU2r_8?usp=sharing','done');
