insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('26EVE8','ov1-2026','EVENT','8','Naina','Mempersiapkan dan menjadi MC Games dengan koordinasi dengan MC Games HIMASTA','2026-05-09',null,null,null,'Games berupa PPT, Konsep game dibebaskan dengan syarat dapat dimainkan oleh semua peserta OV, nantinya game akan memiliki tim sesuai Pasangan Departemen FGD Evaluasi dari OV sebelumnya : MC dan penghitung poin susah menentukan tim mana yang mengangkat tangan duluan untuk menjawab gamesnya, Contoh Game sebelumnya : OV 2024 Ormawa Visit Game','Tebak Gaya, kasih kata kategori (dalam 1 grup fgd yg maju) misalnya berenang (gaboleh gerakan yg sama) 9 kelompok fgd https://canva.link/n0mald0iv1vwod0 Kontak nomor MC Games HIMASTA','done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('26EVE9','ov1-2026','EVENT','9','Mazaya','Menjadi Petugas Penghitung Poin Games dan Menentukan Pemenang Games','2026-05-29',null,'2026-05-29',null,'Petugas akan mencatat poin atau kredit dari tim yang menjawab benar, tim akan disesuaikan dengan Pasangan Departemen FGD. Outputnya akan hanya ada 1 tim pemenang atau 2 Departemen Himpunan yang sepasang FGD',null,'done');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('26EVE10','ov1-2026','EVENT','10','Izzan','Menjadi MC, membuat Script MC dan koordinasi dengan MC HIMASTA','2026-05-09',null,'2026-05-16',null,'Master of Ceremony berjumlah 2 Orang, satu dari HMSI dan satu lagi dari Himpunan Eksternal. Gender MC harus berlawanan Untuk script MC diperbolehkan memilih 2 jenis, diprint atau baca pakai Handphone, karena bedasarkan Evaluasi OV sebelumnya, script MC sudah diprint dan dilaminating namun perlu banyak revisi dan akhirnya print ulang. Dokumen Script MC harus publik dan linknya diinput di kolom result dan superlink Contoh Script MC OV sebelumnya : SCRIPT MC ORMAWA VISIT HMSI X HMTG','Kontak nomor MC acara HIMASTA','ongoing');
insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('26EVE11','ov1-2026','EVENT','11','Mas Fadhiil','Pembuatan Google Form feedback acara','2026-05-09',null,null,null,'Google Form Feedback nantinya diubah ke kode QR yang ditampilkan pada akhir acara, jika sudah jadi taro QR pada Slide PPT dan sampaikan Operator untuk ditampilkan Feedback & Kesan Pesan HMSI x HMTG','https://docs.google.com/forms/d/1ZcT6Mb56y0JZw6_tb-4oL5nrMUE59udIcmRKThL-vKE/edit#responses','done');
