insert into tasks(source_id,event_id,division,no,pic,title,start_date,start_raw,end_date,end_raw,notes,result,status) values ('26EVE171','ov1-2026','EVENT',null,'Ali','Alokasi tempat duduk tiap Departemen di Ruangan Utama','2026-05-09',null,'2026-05-16',null,'Konsepnya ialah memetakan tempat duduk dari HMSI dan Himpunan Eksternal, mereka duduk per pasangan Departemen Himpunannya. Outputnya ada dua jenis dokumen, peta tempat duduk pasangan Departemen Himpunan dan penanda tempat duduk per pasangan Departemen. Nantinya tempat duduk mereka akan ditempelkan kertas print pasangan Departemen Himpunannya','Plotingan tempat duduk selama acara NOTE : 1. Meminta daftar peserta dari LO 2. Meminta foto tempat(Lokasi acara) dari mas Burhan','done');
