insert into faqs(question,answer,"order") values ('Apa itu Ormawa Visit?','Ormawa Visit adalah kegiatan kunjungan antar Organisasi Mahasiswa (Ormawa) yang bertujuan untuk berbagi informasi, melakukan benchmarking sistem organisasi dan program kerja, memperluas relasi, serta membuka peluang kolaborasi antar himpunan.',0);
insert into faqs(question,answer,"order") values ('Berapa kali kita Ormawa Visit dalam satu kali kabinet?','Untuk saat ini minimal 2 Kali, satu kali ke himpunan luar ITS dan satu kali ke himpunan dalam ITS. Jumlah ini dapat berubah.',1);
insert into faqs(question,answer,"order") values ('Mengapa kita tidak OV ke Universitas top di Indonesia seperti UI UGM ITB?','Alasan utamanya ialah Anggaran dan Transportasi jika dalam konteks kita yang pergi kesana, karena Ormawa Visit tidak hanya mengajak EA tetapi seluruh HMSI. Namun tidak ada salahnya mengusahakan hal ini terjadi.',2);
insert into faqs(question,answer,"order") values ('Apa saja faktor yang menentukan sebuah jurusan layak kita kunjungi?','1. Kesesuaian Departemen Himpunan 2. Mendapatkan Insight/Memberi Insight 3. Lokasi Universitas 4. Kesesuaian Timeline 5. Kesesuaian Matakuliah',3);
insert into faqs(question,answer,"order") values ('Lebih baik mana, OV offline atau OV online?','Bedasarkan pengalamanku (padil), OV offline lebih baik dalam berbagai faktor, peserta lebih mendapat relasi dan koneksi saat bertemu tatap muka dibanding online. Online dapat dijadikan opsi jika memang terkendala dari berbagai faktor dan merupakan pilihan terakhir',4);
insert into faqs(question,answer,"order") values ('Apa saja divisi yang bekerja dalam Ormawa Visit?','1. Liaison Officer/Hubungan Masyarakat 2. Event/Acara 3. Consumption/Konsumsi 4. Operational/Kamzin Logistik 5. Creative/PDD',5);
insert into faqs(question,answer,"order") values ('Apa itu FGD (Focus Group Discussion)?','FGD merupakan salah satu agenda kecil dalam pelaksanaan hari H OV, metodenya memasangkan Departemen HMSI dengan Departemen Himpunan Eksternal yang memiliki kesamaan dalam berbagai faktor, tujuannya untuk menjalin relasi dan mendapat serta memberikan insight.',6);
insert into faqs(question,answer,"order") values ('Apa itu Creative Corner?','CC merupakan alat untuk para peserta melampiaskan sisi seninya pada pelaksanaan Ormawa Visit, peserta dibolehkan menulis atau menggambar apapun selama tidak mengandung SARA. Biasanya CC berupa Papan Tulis dengan Spidol serta Sticky Notes.',7);
insert into faqs(question,answer,"order") values ('Apa itu Photobooth OV?','Berupa Photobooth tanpa print yang dapat digunakan peserta saat acara maupun selesai acara, nantinya foto-foto akan terkumpul lewat Gdrive yang dapat diakses lewat scan QR code. Foto akan memiliki twibbon tema OV.',8);
insert into faqs(question,answer,"order") values ('Jika aku sudah selesai dengan tugasku, dimana aku harus mengirimnya?','Secara general hasilnya diinput pada kolom ''Result'' di WBS lalu mengganti statusnya menjadi done, tetapi jika hasilnya perlu didokumentasikan, maka input juga pada sheet LINK agar yang lain mudah mencarinya. Buat dokumen menjadi Akses Publik.',9);
insert into faqs(question,answer,"order") values ('Sheet mana yang boleh aku edit pada Spreadsheet OV ini?','Sheet WBS & Sheet Spesifik Divisi pada kolom Result & Status lalu juga Sheet LINK. Sheet selain ini dapat diedit menggunakan Email EA (Fungsionaris) & bisa juga request ke PIC OV.',10);
insert into faqs(question,answer,"order") values ('Aku punya pertanyaan spesifik untuk tugasku, kemana aku harus bertanya?','Baca dulu kolom ''Important Notes'' pada sheet WBS yang sudah disiapkan, kemungkinan besar pertanyaan sudah dijawab, jika ternyata belum terjawab, tanyakan kepada fungsionaris yang menemani kamu di tugas tersebut. Atau tentu saja bisa bertanya kepada PIC OV.',11);
insert into faqs(question,answer,"order") values ('Aku punya pertanyaan yang tidak ada di sheet FAQ ini','Tanyakan apapun pertanyaanmu tersebut kepada PIC OV atau Staffli OV yang menemani, jangan malu bertanya ya :)',12);
